using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedDatabase(_context);
            _controller = new StudentsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(3, model.Count);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsDescendingOrder()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_SortByDateAsc_ReturnsDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Alexander", model[0].LastName); // 2010
            Assert.Equal("Alonso", model[1].LastName);    // 2012
            Assert.Equal("Anand", model[2].LastName);     // 2013
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anand", model[0].LastName);     // 2013
            Assert.Equal("Alonso", model[1].LastName);    // 2012
            Assert.Equal("Alexander", model[2].LastName); // 2010
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchWithNoMatch_ReturnsEmpty()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageToOne()
        {
            var result = _controller.Index(null, null, "Al", 5) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchStringUsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParms()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_SortByDate_SetsDateSortParmToDesc()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_Pagination_RespectsPageSize()
        {
            // Add more students to exceed page size
            for (int i = 0; i < 12; i++)
            {
                _context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i:D2}",
                    EnrollmentDate = DateTime.Now
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 1) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

            Assert.Equal(10, model.Count);
            Assert.True(model.HasNextPage);
            Assert.False(model.HasPreviousPage);
        }

        [Fact]
        public void Index_Page2_HasPreviousPage()
        {
            for (int i = 0; i < 12; i++)
            {
                _context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i:D2}",
                    EnrollmentDate = DateTime.Now
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

            Assert.True(model.HasPreviousPage);
            Assert.False(model.HasNextPage);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result!.Model);
            Assert.Equal(student.ID, model.ID);
            Assert.NotNull(model.Enrollments);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result!.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Contains(_context.Students, s => s.LastName == "Student");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Student>(result!.Model);
        }

        [Fact]
        public void Create_Post_MinDateValue_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
