using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedDatabase(_context);

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _mockLogger = new Mock<ILogger<CoursesController>>();

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result!.Model);
            Assert.Equal(2, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(1050, model.CourseID);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result!.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
            var selectList = Assert.IsType<SelectList>(_controller.ViewBag.DepartmentID);
            Assert.Single(selectList);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.NotNull(_context.Courses.Find(9999));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9998, DepartmentID = 1 };

            var result = _controller.Create(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFileAndRedirects()
        {
            var course = new Course
            {
                CourseID = 9997,
                Title = "Course With Image",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", 1024, "image/jpeg");

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            var saved = _context.Courses.Find(9997);
            Assert.NotNull(saved);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved!.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 9996,
                Title = "Course Bad Image",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.txt", 1024, "text/plain");

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedImage_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 9995,
                Title = "Course Oversize",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024, "image/jpeg");

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit((int?)1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(1050, model.CourseID);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit((int?)9999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1050)!;
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(updated, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _controller.Edit(course, null!) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_WithValidImage_SavesNewAndRedirects()
        {
            var course = _context.Courses.Find(1050)!;
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("new_image.png", 2048, "image/png");

            var result = _controller.Edit(updated, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.exe", 1024, "application/octet-stream");

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_WithOversizedImage_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024, "image/jpeg");

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(1050, model.CourseID);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImagePath_DeletesFileAndRedirects()
        {
            // Set up a course with an image path
            var course = _context.Courses.Find(4022)!;
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var filePath = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(filePath, "fake image data");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(4022) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.False(File.Exists(filePath));
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long length, string contentType)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => { /* simulate writing */ });
            return mockFile;
        }

        #endregion
    }
}

