using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            SeedInstructorData();
            _controller = new InstructorsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedInstructorData()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            _context.Departments.Add(dept);

            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.AddRange(instructor1, instructor2);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            _context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor1.ID,
                CourseID = 1050
            });
            _context.SaveChanges();

            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            _context.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = 1050,
                Grade = Grade.A
            });
            _context.SaveChanges();
        }

        #region Index

        [Fact]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result!.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            var result = _controller.Index(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result!.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
            Assert.Equal(instructor.ID, (int)_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            var result = _controller.Index(instructor.ID, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result!.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_ReturnsViewWithCourseAssignments()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            Assert.Single(courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_WithNoCourses_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_ValidInstructor_WithCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Teacher",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, new[] { "1050" }) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            var saved = _context.Instructors.First(i => i.LastName == "Teacher");
            Assert.Single(saved.CourseAssignments);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            var result = _controller.Edit((int?)instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal("Abercrombie", model.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Fakhouri");
            var id = instructor.ID;

            var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Null(_context.Instructors.Find(id));
        }

        [Fact]
        public void DeleteConfirmed_InstructorWithDepartment_ClearsDepartmentAdministrator()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var dept = _context.Departments.First();
            dept.InstructorID = instructor.ID;
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.First();
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

