using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            // Drain the static notification queue to avoid cross-test pollution
            var service = new Services.NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();

            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithNoNotifications()
        {
            // Drain any existing notifications first
            var drainService = new Services.NotificationService();
            while (drainService.ReceiveNotification() != null) { }

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);

            // Check it has success = true via dynamic or reflection
            var successProp = json!.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp!.GetValue(json)!);

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp!.GetValue(json)!);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Drain first
            var drainService = new Services.NotificationService();
            while (drainService.ReceiveNotification() != null) { }

            // Add some notifications via the service
            var service = new Services.NotificationService();
