using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any existing notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue to avoid leaking into other tests
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        #region SendNotification

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification!.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "1050", EntityOperation.UPDATE, "teacher");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 1050", notification!.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_CorrectMessage()
        {
            _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("New Student 'Jane Smith' has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_CorrectMessage()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Course 'Chemistry' has been updated", notification!.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_CorrectMessage()
        {
            _service.SendNotification("Department", "1", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been deleted", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_CreateMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("New Student (ID: 42) has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.InRange(notification!.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_DefaultIsReadFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.False(notification!.IsRead);
        }

        #endregion

        #region ReceiveNotification

        [Fact]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
            Assert.Equal("C", third!.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        #endregion

        #region MarkAsRead

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        #endregion

        #region Dispose

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        #endregion

        #region Overload without display name

        [Fact]
        public void SendNotification_TwoParamOverload_Works()
        {
            _service.SendNotification("Instructor", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification!.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }

        #endregion
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any existing notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue to avoid leaking into other tests
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        #region SendNotification

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification!.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "1050", EntityOperation.UPDATE, "teacher");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 1050", notification!.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_CorrectMessage()
        {
            _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("New Student 'Jane Smith' has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_CorrectMessage()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Course 'Chemistry' has been updated", notification!.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_CorrectMessage()
        {
            _service.SendNotification("Department", "1", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been deleted", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_CreateMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("New Student (ID: 42) has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.InRange(notification!.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_DefaultIsReadFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.False(notification!.IsRead);
        }

        #endregion

        #region ReceiveNotification

        [Fact]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
            Assert.Equal("C", third!.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        #endregion

        #region MarkAsRead

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        #endregion

        #region Dispose

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        #endregion

        #region Overload without display name

        [Fact]
        public void SendNotification_TwoParamOverload_Works()
        {
            _service.SendNotification("Instructor", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification!.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }

        #endregion
    }
}

