using System;
using System.Collections.Generic;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ReturnsLastCommaFirst()
        {
            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander"
            };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = DateTime.Parse("2020-01-15");
            var student = new Student { EnrollmentDate = date };

            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_HireDate_CanBeSet()
        {
            var date = DateTime.Parse("2020-01-15");
            var instructor = new Instructor { HireDate = date };

            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(student.Enrollments);
            Assert.Empty(student.Enrollments);
        }

        [Fact]
        public void Instructor_CourseAssignments_CanBeInitialized()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/test.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties_CanBeInitialized()
        {
            var course = new Course
            {
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>(),
                Department = new Department { Name = "Test" }
            };

            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { InstructorID = null };

            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_RowVersion_CanBeSet()
        {
            var version = new byte[] { 1, 2, 3, 4 };
            var dept = new Department { RowVersion = version };

            Assert.Equal(version, dept.RowVersion);
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment { Grade = null };

            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValues_AreValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };

            Assert.Equal(grade, enrollment.Grade);
        }

        #endregion

        #region CourseAssignment

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Smith 17", oa.Location);
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_IsRead_CanBeTrue()
        {
            var readTime = DateTime.Now;
            var notification = new Notification
            {
                IsRead = true,
                ReadAt = readTime
            };

            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE)]
        [InlineData(EntityOperation.UPDATE)]
        [InlineData(EntityOperation.DELETE)]
        public void EntityOperation_AllValues_AreValid(EntityOperation op)
        {
            Assert.True(Enum.IsDefined(typeof(EntityOperation), op));
        }

        #endregion

        #region ErrorViewModel

        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };

            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenNull()
        {
            var model = new ErrorViewModel { RequestId = null };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };

            Assert.False(model.ShowRequestId);
        }

        #endregion

        #region ViewModels

        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var date = DateTime.Parse("2020-09-01");
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };

            Assert.Equal(date, group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_NullableDate_CanBeNull()
        {
            var group = new EnrollmentDateGroup { EnrollmentDate = null };

            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        #endregion
    }
}

